import test from 'node:test';
import assert from 'node:assert/strict';

import { parseCompressibleTypes } from '../src/compression-config.mjs';
import { matchesConfiguredType } from '../src/content-type-match.mjs';

test('comma-separated deployment values ignore surrounding whitespace', () => {
  assert.deepEqual(
    parseCompressibleTypes(' application/json, text/csv , text/plain '),
    ['application/json', 'text/csv', 'text/plain']
  );
});

test('Content-Type parameters do not change the configured media type match', () => {
  assert.equal(
    matchesConfiguredType('text/csv; charset=utf-8', ['text/csv']),
    true
  );
  assert.equal(
    matchesConfiguredType('application/json; profile=compact', ['application/json']),
    true
  );
  assert.equal(
    matchesConfiguredType('image/png; profile=compact', ['application/json']),
    false
  );
});
